import request from "supertest";
import app from "../../index.js";
import Article from "../../models/articleModel.js";
import mongoose from "mongoose";

describe("articleController.incrementViews", () => {
  let testArticle;
  let validCategory;

  beforeAll(async () => {
    // Ensure we're connected to test database
    if (mongoose.connection.readyState === 0) {
      await mongoose.connect(process.env.MONGODB_TEST_URI || "mongodb://localhost:27017/test");
    }

    // Dynamically get a valid category from the schema
    const categoryPath = Article.schema.path('category');
    if (categoryPath && categoryPath.enumValues && categoryPath.enumValues.length > 0) {
      validCategory = categoryPath.enumValues[0]; // Use the first valid enum value
      console.log(`Using valid category: ${validCategory}`);
      console.log(`All valid categories: ${categoryPath.enumValues.join(', ')}`);
    } else {
      validCategory = undefined; // Category might not be required or have no enum
    }
  });

  beforeEach(async () => {
    // Get all required fields from schema
    const schemaObj = Article.schema.obj;
    
    // Build test article with dynamic required fields
    const testData = {
      title: "Test Article for Views",
      content: "Test content for the article body",
      description: "Test description of the article",
      views: 5,
    };

    // Add common fields that might be required
    if (Article.schema.path('link')) testData.link = "http://test.com/article123";
    if (Article.schema.path('url')) testData.url = "http://test.com/article123";
    if (Article.schema.path('source')) testData.source = "Test Source";
    if (Article.schema.path('author')) testData.author = "Test Author";
    if (Article.schema.path('urlToImage')) testData.urlToImage = "http://test.com/image.jpg";
    if (Article.schema.path('publishedAt')) testData.publishedAt = new Date();
    if (Article.schema.path('location')) testData.location = "Global";
    if (Article.schema.path('category') && validCategory) testData.category = validCategory;

    testArticle = await Article.create(testData);
  });

  afterEach(async () => {
    // Clean up after each test
    if (testArticle && testArticle._id) {
      try {
        await Article.findByIdAndDelete(testArticle._id);
      } catch (err) {
        console.error('Cleanup error:', err.message);
      }
    }
  });

  afterAll(async () => {
    // Close connection after all tests
    await mongoose.connection.close();
  });

  // ================================
  // 1️⃣ SUCCESS CASE
  // ================================
  test("should increment views successfully", async () => {
    const res = await request(app).post(`/api/news/${testArticle._id}/view`);

    expect(res.status).toBe(200);
    
    // Verify the view was incremented
    const updatedArticle = await Article.findById(testArticle._id);
    expect(updatedArticle.views).toBe(6); // 5 + 1
  });

  // ================================
  // 2️⃣ NOT FOUND CASE
  // ================================
  test("should return 404 when article not found", async () => {
    const fakeId = new mongoose.Types.ObjectId();
    const res = await request(app).post(`/api/news/${fakeId}/view`);

    expect(res.status).toBe(404);
  });

  // ================================
  // 3️⃣ INVALID ID CASE
  // ================================
  test("should return 500 on invalid ID format", async () => {
    const res = await request(app).post("/api/news/invalid-id-123/view");

    expect(res.status).toBe(500);
  });
});

